    diagnostics: ["Expect skin biopsy with direct immunofluorescence showing IgG deposits at intercellular junctions", "Monitor positive Nikolsky sign (skin shearing with lateral pressure)", "Expect serum anti-desmoglein antibody titers (correlate with disease activity)", "Monitor oral mucosa for erosions (often the first site involved)", "Expect indirect immunofluorescence on serum", "Monitor for secondary wound infections"],
    management: ["Administer systemic corticosteroids as ordered (first-line treatment)", "Administer steroid-sparing immunosuppressants as ordered (azathioprine, mycophenolate)", "Administer rituximab as ordered for refractory cases", "Provide meticulous wound care for denuded skin areas", "Maintain nutritional support (high-protein, high-calorie diet)", "Coordinate multidisciplinary care (dermatology, oral medicine)"],
    nursingActions: ["Assess skin and mucous membranes for new blisters and erosions daily", "Handle the patient gently to avoid inducing new blisters (Nikolsky phenomenon)", "Provide gentle oral care with soft-bristled brush and non-irritating mouthwash", "Monitor for signs of infection at erosion sites (increased erythema, purulence, fever)", "Monitor for immunosuppressive therapy side effects (infection, bone marrow suppression)", "Maintain fluid balance and nutritional support, especially with extensive oral involvement", "Provide emotional support for chronic, disfiguring condition"],
    signs: { left: ["Flaccid, fragile blisters that rupture easily", "Painful erosions on denuded skin", "Positive Nikolsky sign", "Oral mucosal erosions (often first manifestation)"], right: ["Painful oral erosions impairing eating and swallowing", "Non-healing erosions without treatment", "No scarring (suprabasal cleavage preserves basement membrane)", "Widespread distribution when severe"] },
